alter table public.titles add column if not exists tmdb_id int;
alter table public.titles add column if not exists imdb_id text unique;
alter table public.titles add column if not exists imdb_rank int;
alter table public.titles add column if not exists imdb_rating numeric(3,1);
alter table public.titles add column if not exists imdb_votes int;
create index if not exists titles_imdb_rank_idx on public.titles (type, imdb_rank) where imdb_rank is not null;

insert into public.titles (
  slug, title, type, tmdb_id, imdb_id, imdb_rank, imdb_rating, imdb_votes, year, country, network, duration,
  rating, synopsis, poster_path, backdrop_path, genre_names, is_published, is_featured, is_trending, is_recently_added
) values
('the-shawshank-redemption-1994', 'The Shawshank Redemption', 'movie', 278, 'tt0111161', 1, 9.3, 3196742, 1994, 'Unknown', 'Movie', '2j 22m', 'IMDb 9.3', 'Imprisoned in the 1940s for the double murder of his wife and her lover, upstanding banker Andy Dufresne begins a new life at the Shawshank prison, where he puts his accounting skills to work for an amoral warden. During his long stretch in prison, Dufresne comes to be admired by the other inmates -- including an older prisoner named Red -- for his integrity and unquenchable sense of hope.', '/9cqNxx0GxF0bflZmeSMuL5tnGzr.jpg', '/zfbjgQE1uSd9wiPTX4VzsLi0rGG.jpg', array['Drama'], true, true, true),
('the-godfather-1972', 'The Godfather', 'movie', 238, 'tt0068646', 2, 9.2, 2229956, 1972, 'Unknown', 'Movie', '2j 55m', 'IMDb 9.2', 'Patriark tua dari dinasti kejahatan terorganisir di New York City pascaperang mengalihkan kendali kerajaan klandestinnya kepada putra bungsunya yang enggan.', '/3bhkrj58Vtu7enYsRolD1fZdja1.jpg', '/ejdD20cdHNFAYAN2DlqPToXKyzx.jpg', array['Crime', 'Drama'], true, true, true),
('the-dark-knight-2008', 'The Dark Knight', 'movie', 155, 'tt0468569', 3, 9.1, 3176249, 2008, 'Unknown', 'Movie', '2j 32m', 'IMDb 9.1', 'Batman raises the stakes in his war on crime. With the help of Lt. Jim Gordon and District Attorney Harvey Dent, Batman sets out to dismantle the remaining criminal organizations that plague the streets. The partnership proves to be effective, but they soon find themselves prey to a reign of chaos unleashed by a rising criminal mastermind known to the terrified citizens of Gotham as the Joker.', '/qJ2tW6WMUDux911r6m7haRef0WH.jpg', '/cfT29Im5VDvjE0RpyKOSdCKZal7.jpg', array['Crime', 'Thriller'], true, true, true),
('the-chaos-class-1975', 'The Chaos Class', 'movie', 83651, 'tt0252487', 4, 9.1, 46317, 1975, 'Unknown', 'Movie', '1j 25m', 'IMDb 9.1', 'A group of affluent private school slackers enjoy a prankster lifestyle until a tough new disciplinarian headmaster arrives.', '/t2xLuEeZhy4uyiWIFT9D4mmyEA8.jpg', '/9u9XcPaeOvPcelm8RmMarEgvIAk.jpg', array['Comedy'], true, true, true),
('the-lord-of-the-rings-the-return-of-the-king-2003', 'The Lord of the Rings: The Return of the King', 'movie', 122, 'tt0167260', 5, 9.0, 2168090, 2003, 'Unknown', 'Movie', '3j 21m', 'IMDb 9.0', 'Aragorn dinyatakan sebagai pewaris raja-raja kuno saat ia, Gandalf dan anggota-anggota lain dari persekutuan yang rusak berjuang untuk menyelamatkan Gondor dari pasukan Sauron. Sementara itu, Frodo dan Sam membawa cincin itu lebih dekat ke jantung Mordor, kerajaan penguasa gelap.', '/rCzpDGLbOoPwLjy3OAm5NUPOTrC.jpg', '/2u7zbn8EudG6kLlBzUYqP8RyFU4.jpg', array['Adventure', 'Drama', 'Fantasy'], true, true, true),
('schindler-s-list-1993', 'Schindler''s List', 'movie', 424, 'tt0108052', 6, 9.0, 1586996, 1993, 'Unknown', 'Movie', '3j 15m', 'IMDb 9.0', 'The true story of how businessman Oskar Schindler saved over a thousand Jewish lives from the Nazis while they worked as slaves in his factory during World War II.', '/sF1U4EUQS8YHUYjNl3pMGNIQyr0.jpg', '/zb6fM1CX41D9rF9hdgclu0peUmy.jpg', array['Biography', 'Drama', 'History'], false, true, true),
('the-godfather-part-ii-1974', 'The Godfather Part II', 'movie', 240, 'tt0071562', 7, 9.0, 1496738, 1974, 'Unknown', 'Movie', '3j 22m', 'IMDb 9.0', 'In the continuing saga of the Corleone crime family, a young Vito Corleone grows up in Sicily and in 1910s New York. In the 1950s, Michael Corleone attempts to expand the family business into Las Vegas, Hollywood and Cuba.', '/hek3koDUyRQk7FIhPXsa6mT2Zc3.jpg', '/kGzFbGhp99zva6oZODW5atUtnqi.jpg', array['Crime', 'Drama'], false, true, true),
('12-angry-men-1957', '12 Angry Men', 'movie', 389, 'tt0050083', 8, 9.0, 986312, 1957, 'Unknown', 'Movie', '1j 36m', 'IMDb 9.0', 'Setelah argumen penutup dalam persidangan pembunuhan, 12 anggota juri harus berunding, dengan vonis bersalah yang berarti kematian bagi terdakwa, seorang remaja dari kota. Ketika belasan orang itu mencoba untuk mencapai keputusan bulat saat diasingkan di sebuah ruangan, seorang juri meragukan beberapa elemen dari kasus tersebut. Masalah pribadi segera muncul ke permukaan, dan konflik mengancam untuk menggagalkan proses rumit yang akan menentukan nasib seorang anak laki-laki.', '/zhG3vKWyDRaZYoaww1UVAi29T9h.jpg', '/qqHQsStV6exghCM7zbObuYBiYxw.jpg', array['Crime', 'Drama'], false, true, true),
('attack-on-titan-the-last-attack-2024', 'Attack on Titan: THE LAST ATTACK', 'movie', 1333100, 'tt33175825', 9, 9.0, 30549, 2024, 'Unknown', 'Movie', '2j 25m', 'IMDb 9.0', 'A colossal-sized omnibus film bringing together the last two episodes of Attack on Titan in the franchise''s first-ever theatrical experience. After venturing beyond the walls and separated from his comrades, Eren finds himself inspired by this new truth and plots the "Rumbling," a terrifying plan to eradicate every living thing in the world. With the fate of the world hanging in the balance, a motley crew of Eren''s former comrades and enemies scramble to halt his deadly mission. The only question is, can they stop him?', '/wgwldDDlTDDMrluOMkpSA8lyKjv.jpg', '/nB6IR9XfdRpVRKCz85uT97EjgwB.jpg', array['Action', 'Adventure', 'Animation'], false, true, true),
('the-lord-of-the-rings-the-fellowship-of-the-ring-2001', 'The Lord of the Rings: The Fellowship of the Ring', 'movie', 120, 'tt0120737', 10, 8.9, 2210277, 2001, 'Unknown', 'Movie', '2j 58m', 'IMDb 8.9', 'Hobbit muda Frodo Baggins, setelah mewarisi cincin misterius dari pamannya, Bilbo, harus meninggalkan rumahnya agar tidak jatuh ke tangan penciptanya yang jahat. Sepanjang jalan, persekutuan dibentuk untuk melindungi ringbearer dan memastikan bahwa cincin itu tiba di tujuan akhirnya: Mt. Doom, satu-satunya tempat di mana ia bisa dihancurkan.', '/6oom5QYQ2yQTMJIbnvbkBL9cHo6.jpg', '/oiwc338EoBgS4sEI2ixAny4KQKg.jpg', array['Adventure', 'Drama', 'Fantasy'], false, true, true),
('david-attenborough-a-life-on-our-planet-2020', 'David Attenborough: A Life on Our Planet', 'movie', 664280, 'tt11989890', 11, 8.9, 36186, 2020, 'Unknown', 'Movie', '1j 23m', 'IMDb 8.9', 'The story of life on our planet by the man who has seen more of the natural world than any other. In more than 90 years, Attenborough has visited every continent on the globe, exploring the wild places of our planet and documenting the living world in all its variety and wonder. Addressing the biggest challenges facing life on our planet, the film offers a powerful message of hope for future generations.', '/zSKwyUDKDHiFU5syTTvQRDcGBPS.jpg', '/hHL4pwGzYS4njLpXhIjfc9skAQJ.jpg', array['Biography', 'Documentary'], false, true, true),
('mirror-game-2016', 'Mirror Game', 'movie', 418325, 'tt5354160', 12, 8.9, 31047, 2016, 'Unknown', 'Movie', '2j 27m', 'IMDb 8.9', 'Ayna is an actor and the prison is his stage. He slips into the characters of the powerful convicted in exchange of money and take their place in prison. This strange profession is borne out of a society that doesn''t give him a chance to follow his passion of acting, but forces him to act in the real life. Falling in love with the girl next door changes his life equation and he decides to end this career with one last performance. But this one takes him too deep in the rabbit hole. The story unfolds on how an underdog survives in a society that is merciless and struggles his way out from the clutch of crime game which he is a part too.', '/1Cz5Q7PH2JklNV7OzMkTenPGrEf.jpg', '/weDuRCMSCXgVQNQmSsfCQtdAmoK.jpg', array['Crime', 'Mystery', 'Thriller'], false, true, true),
('tosun-pasha-1976', 'Tosun Pasha', 'movie', 38794, 'tt0253828', 13, 8.9, 26433, 1976, 'Unknown', 'Movie', '1j 30m', 'IMDb 8.9', 'Late 19th century in Alexandria. Two traditionally rival Turkish families, "Seferoglu"s and "Tellioglu"s are competing for the "Green Valley". The winner will be determined by Daver Bey, who has a beautiful young daughter, Leyla. Both families try to arrange a marriage between a man from their family and Leyla, so that Daver Bey will be inclined to give the green valley to his "relatives". Tellioglus, who are behind in the race, desperately find a final solution: They will fake their idiotic butler, Saban, as the highest ranked Ottoman soldier in Egypt: Tosun Pasha.', '/zqgB6E4yynfxkzzOurzC0VRObxf.jpg', '/kiu0xIcu9Rju9HTWSJOo8Svg9aW.jpg', array['Comedy', 'History'], false, true, true),
('inception-2010', 'Inception', 'movie', 27205, 'tt1375666', 14, 8.8, 2824348, 2010, 'Unknown', 'Movie', '2j 28m', 'IMDb 8.8', 'Cobb, seorang pencuri terampil yang melakukan spionase perusahaan dengan menyusup ke alam bawah sadar targetnya ditawarkan kesempatan untuk mendapatkan kembali kehidupan lamanya sebagai pembayaran untuk tugas yang dianggap mustahil: "permulaan", penanaman ide orang lain ke dalam alam bawah sadar target.', '/xlaY2zyzMfkhk0HSC5VUwzoZPU1.jpg', '/8ZTVqvKDQ8emSGUEMjsS4yHAwrp.jpg', array['Adventure', 'Sci-Fi', 'Thriller'], false, true, true),
('fight-club-1999', 'Fight Club', 'movie', 550, 'tt0137523', 15, 8.8, 2615814, 1999, 'Unknown', 'Movie', '2j 19m', 'IMDb 8.8', 'Seorang pekerja kantoran yang menderita insomnia dan pembuat sabun yang sangat peduli membentuk klub pertarungan bawah tanah yang berkembang menjadi lebih banyak lagi.', '/jSziioSwPVrOy9Yow3XhWIBDjq1.jpg', '/xRyINp9KfMLVjRiO5nCsoRDdvvF.jpg', array['Crime', 'Drama', 'Thriller'], false, true, true),
('forrest-gump-1994', 'Forrest Gump', 'movie', 13, 'tt0109830', 16, 8.8, 2502882, 1994, 'Unknown', 'Movie', '2j 22m', 'IMDb 8.8', 'Forrest Gump, seorang pria ber IQ rendah - namun baik hati, bergabung dengan tentara untuk mengabdi. Namun, benaknya seolah tidak bisa berhenti memikirkan sang kekasih masa kecilnya, Jenny Curran.', '/Cw4hIUIAmSYfK9QfaUW5igp9La.jpg', '/66Kn4XWhkuPkJxOJyPEx4U2CUfN.jpg', array['Drama', 'Romance'], false, true, true),
('pulp-fiction-1994', 'Pulp Fiction', 'movie', 680, 'tt0110912', 17, 8.8, 2439449, 1994, 'Unknown', 'Movie', '2j 34m', 'IMDb 8.8', 'A burger-loving hit man, his philosophical partner, a drug-addled gangster''s moll and a washed-up boxer converge in this sprawling, comedic crime caper. Their adventures unfurl in three stories that ingeniously trip back and forth in time.', '/vQWk5YBFWF4bZaofAbv0tShwBvQ.jpg', '/suaEOtk1N1sgg2MTM7oZd2cfVp3.jpg', array['Crime', 'Drama'], false, true, true),
('the-lord-of-the-rings-the-two-towers-2002', 'The Lord of the Rings: The Two Towers', 'movie', 121, 'tt0167261', 18, 8.8, 1961603, 2002, 'Unknown', 'Movie', '2j 59m', 'IMDb 8.8', 'Frodo dan Sam sedang berjalan ke Mordor untuk menghancurkan Satu Cincin Kekuasaan sementara Gimli, Legolas dan Aragorn mencari Merry dan Pippin yang ditangkap Orc. Selama ini, penyihir jahat Saruman menunggu anggota Fellowship di Menara Orthanc di Isengard.', '/5VTN0pR8gcqV3EPUHHfMGnJYN9L.jpg', '/6G73mNyooWAEQTpckPSnFxFoNmc.jpg', array['Adventure', 'Drama', 'Fantasy'], false, true, true),
('the-good-the-bad-and-the-ugly-1966', 'The Good, the Bad and the Ugly', 'movie', 429, 'tt0060196', 19, 8.8, 891500, 1966, 'Unknown', 'Movie', '2j 58m', 'IMDb 8.8', 'While the Civil War rages on between the Union and the Confederacy, three men – a quiet loner, a ruthless hitman, and a Mexican bandit – comb the American Southwest in search of a strongbox containing $200,000 in stolen gold.', '/bX2xnavhMYjWDoZp1VM6VnU1xwe.jpg', '/Adrip2Jqzw56KeuV2nAxucKMNXA.jpg', array['Adventure', 'Drama', 'Western'], false, true, true),
('interstellar-2014', 'Interstellar', 'movie', 157336, 'tt0816692', 20, 8.7, 2541567, 2014, 'Unknown', 'Movie', '2j 49m', 'IMDb 8.7', 'Antarbintang mencatat petualangan sekelompok penjelajah yang memanfaatkan lubang cacing yang baru ditemukan untuk melampaui batasan perjalanan ruang angkasa manusia dan menaklukkan jarak yang luas yang terlibat dalam pelayaran antarbintang.', '/yQvGrMoipbRoddT0ZR8tPoR7NfX.jpg', '/2ssWTSVklAEc98frZUQhgtGHx7s.jpg', array['Adventure', 'Drama', 'Sci-Fi'], false, true, true),
('the-matrix-1999', 'The Matrix', 'movie', 603, 'tt0133093', 21, 8.7, 2252453, 1999, 'Unknown', 'Movie', '2j 16m', 'IMDb 8.7', 'Berlatar abad ke-22, The Matrix menceritakan tentang seorang peretas komputer yang bergabung dengan sekelompok pemberontak bawah tanah melawan komputer-komputer besar dan kuat yang kini menguasai bumi.', '/dXNAPwY7VrqMAo51EKhhCJfaGb5.jpg', '/oMsxZEvz9a708d49b6UdZK1KAo5.jpg', array['Action', 'Sci-Fi'], false, false, true),
('star-wars-episode-v-the-empire-strikes-back-1980', 'Star Wars: Episode V - The Empire Strikes Back', 'movie', 1891, 'tt0080684', 22, 8.7, 1507380, 1980, 'Unknown', 'Movie', '2j 04m', 'IMDb 8.7', 'Kisah epik ini berlanjut saat Luke Skywalker, dengan harapan mengalahkan Kekaisaran Galaksi yang jahat, mempelajari cara-cara Jedi dari guru tua Yoda. Namun Darth Vader lebih bertekad dari sebelumnya untuk menangkap Luke. Sementara itu, pemimpin pemberontak Putri Leia, Han Solo yang sombong, Chewbacca, dan droid C-3PO dan R2-D2 dilemparkan ke berbagai tahap penangkapan, pengkhianatan, dan keputusasaan.', '/nNAeTmF4CtdSgMDplXTDPOpYzsX.jpg', '/aJCtkxLLzkk1pECehVjKHA2lBgw.jpg', array['Adventure', 'Fantasy', 'Sci-Fi'], false, false, true),
('goodfellas-1990', 'GoodFellas', 'movie', 769, 'tt0099685', 23, 8.7, 1394837, 1990, 'Unknown', 'Movie', '2j 25m', 'IMDb 8.7', 'Mantan mafia, Henry Hill, menceritakan kisah suka dukanya yang penuh warna tapi brutal dalam keluarga kriminal New York. Impian untuk hidup mewah pun jadi mimpi buruk.', '/9OkCLM73MIU2CrKZbqiT8Ln1wY2.jpg', '/gILte6Zd7m1YneIr6MVhh30S9pr.jpg', array['Biography', 'Crime', 'Drama'], false, false, true),
('12th-fail-2023', '12th Fail', 'movie', 1163258, 'tt23849204', 24, 8.7, 172902, 2023, 'Unknown', 'Movie', '2j 27m', 'IMDb 8.7', 'Based on the true story of IPS officer Manoj Kumar Sharma, 12th Fail sheds limelight on fearlessly embracing the idea of restarting the academic journey despite the setbacks and challenges and reclaiming one''s destiny at a place where millions of students attempt the world''s toughest competitive exam: UPSC.', '/eebUPRI4Z5e1Z7Hev4JZAwMIFkX.jpg', '/6RV2o8PBCEyw9ylOWViV1CtULIF.jpg', array['Biography', 'Drama'], false, false, true),
('777-charlie-2022', '777 Charlie', 'movie', 634120, 'tt7466810', 25, 8.7, 47792, 2022, 'Unknown', 'Movie', '2j 44m', 'IMDb 8.7', 'Dharma is stuck in a rut with his negative and lonely lifestyle and spends each day in the comfort of his loneliness. A pup named Charlie who is naughty and energetic which is a complete contrast with the Dharma’s character enters his life and gives him a new perspective towards it.', '/qArPmXH0aWsT3SEtYl8XrU2Oz48.jpg', '/3Sdi32wfIIOtDz1hYik6bGe1iWC.jpg', array['Adventure', 'Comedy', 'Drama'], false, false, true),
('kill-bill-the-whole-bloody-affair-2004', 'Kill Bill: The Whole Bloody Affair', 'movie', 414419, 'tt6019206', 26, 8.7, 44107, 2004, 'Unknown', 'Movie', '4j 13m', 'IMDb 8.7', 'A former assassin, known simply as The Bride, wakes from a coma four years after her jealous ex-lover Bill attempts to murder her on her wedding day. Fueled by an insatiable desire for revenge, she vows to get even with every person who contributed to the loss of her unborn child, her entire wedding party, and four years of her life. After devising a hit list, The Bride sets off on her quest, enduring unspeakable injury and unscrupulous enemies.', '/nSOJfWJCdVFZQwXQA7RXn7FIIiY.jpg', '/qe4Tp0hURXqiih5AV1kHimXIt3u.jpg', array['Action', 'Crime', 'Thriller'], false, false, true),
('se7en-1995', 'Se7en', 'movie', 807, 'tt0114369', 27, 8.6, 2027153, 1995, 'Unknown', 'Movie', '2j 07m', 'IMDb 8.6', 'Two homicide detectives are on a desperate hunt for a serial killer whose crimes are based on the "seven deadly sins" in this dark and haunting film that takes viewers from the tortured remains of one victim to the next. The seasoned Det. Somerset researches each sin in an effort to get inside the killer''s mind, while his novice partner, Mills, scoffs at his efforts to unravel the case.', '/191nKfP0ehp3uIvWqgPbFmI4lv9.jpg', '/i5H7zusQGsysGQ8i6P361Vnr0n2.jpg', array['Crime', 'Drama', 'Mystery'], false, false, true),
('the-silence-of-the-lambs-1991', 'The Silence of the Lambs', 'movie', 274, 'tt0102926', 28, 8.6, 1726667, 1991, 'Unknown', 'Movie', '1j 58m', 'IMDb 8.6', 'Clarice Starling is a top student at the FBI''s training academy. Jack Crawford wants Clarice to interview Dr. Hannibal Lecter, a brilliant psychiatrist who is also a violent psychopath, serving life behind bars for various acts of murder and cannibalism. Crawford believes that Lecter may have insight into a case and that Starling, as an attractive young woman, may be just the bait to draw him out.', '/uS9m8OBk1A8eM9I042bx8XXpqAq.jpg', '/aYcnDyLMnpKce1FOYUpZrXtgUye.jpg', array['Crime', 'Drama', 'Horror'], false, false, true),
('saving-private-ryan-1998', 'Saving Private Ryan', 'movie', 857, 'tt0120815', 29, 8.6, 1644125, 1998, 'Unknown', 'Movie', '2j 49m', 'IMDb 8.6', 'Delapan Ranger Angkatan Darat AS menyusup ke wilayah yang dikuasai Jerman pada saat Perang Dunia II demi membawa pulang seorang prajurit yang tiga kakaknya telah gugur.', '/uqx37cS8cpHg8U35f9U5IBlrCV3.jpg', '/bdD39MpSVhKjxarTxLSfX6baoMP.jpg', array['Drama', 'War'], false, false, true),
