('the-green-mile-1999', 'The Green Mile', 'movie', 497, 'tt0120689', 31, 8.6, 1564499, 1999, 'Unknown', 'Movie', '3j 09m', 'IMDb 8.6', 'A supernatural tale set on death row in a Southern prison, where gentle giant John Coffey possesses the mysterious power to heal people''s ailments. When the cell block''s head guard, Paul Edgecomb, recognizes Coffey''s miraculous gift, he tries desperately to help stave off the condemned man''s execution.', '/8VG8fDNiy50H4FedGwdSVUPoaJe.jpg', '/b6HWTOxn1xevvyHU2K9ICvaRU6g.jpg', array['Crime', 'Drama', 'Fantasy'], false, false, true),
('terminator-2-judgment-day-1991', 'Terminator 2: Judgment Day', 'movie', 280, 'tt0103064', 32, 8.6, 1286448, 1991, 'Unknown', 'Movie', '2j 17m', 'IMDb 8.6', 'Ten years after the events of the original, a reprogrammed T-800 is sent back in time to protect young John Connor from the shape-shifting T-1000. Together with his mother Sarah, he fights to stop Skynet from triggering a nuclear apocalypse.', '/jFTVD4XoWQTcg7wdyJKa8PEds5q.jpg', '/izkMjmhauFx9DjoBQqM5sM5WAwE.jpg', array['Action', 'Adventure', 'Sci-Fi'], false, false, true),
