('leyla-and-mecnun-2011', 'Leyla and Mecnun', 'series', 40417, 'tt1831164', 25, 9.0, 103725, 2011, 'Unknown', 'TV', '1 Musim', 'IMDb 9.0', 'Leyla ile Mecnun is a Turkish television comedy series. The show is set in Istanbul, Turkey and premiered in 2011 on TRT. The series is a surreal and absurd comedy that revolves around the fictional love story between Leyla and Mecnun.', '/3jPLJJXbFabb29mOxZOK0xctcy6.jpg', '/aEQEIXDmjd9otezUu64VFmpO51K.jpg', array['Adventure', 'Comedy', 'Drama'], false, false, true),
('kota-factory-2019', 'Kota Factory', 'series', 89113, 'tt9432978', 26, 9.0, 92488, 2019, 'Unknown', 'TV', '1 Musim', 'IMDb 9.0', 'In a city of coaching centers known to train India’s finest collegiate minds, an earnest but unexceptional student and his friends navigate campus life.', '/fMBookmwL6HjIgIVTjQ6EMr3pCH.jpg', '/mQEmKXSFlzBlSoYgut0VfjxAzoA.jpg', array['Comedy', 'Drama'], false, false, true),
('clarkson-s-farm-2021', 'Clarkson''s Farm', 'series', 117648, 'tt10541088', 27, 9.0, 86526, 2021, 'Unknown', 'TV', '1 Musim', 'IMDb 9.0', 'Follow Jeremy Clarkson as he embarks on his latest adventure, farming. The man who on several occasions claims to be allergic to manual labour takes on the most manually labour intensive job there is. What could possibly go wrong?', '/toVhyqMT3ICfahE7Ad8obJvZHpX.jpg', '/i50h4Gz6e9BMGak5l6gg5qfIjcv.jpg', array['Comedy', 'Documentary', 'Reality-TV'], false, false, true),
('tvf-pitchers-2015', 'TVF Pitchers', 'series', 63180, 'tt4742876', 28, 9.0, 79787, 2015, 'Unknown', 'TV', '1 Musim', 'IMDb 9.0', 'A story of trials and tribulations of four young entrepreneurs who quit their day jobs in order to pursue their start up venture.', '/w0A288hXCytNIi9Kh7VkKE8MQ1W.jpg', '/AkhbsjGma7KnwN8Z63yqGMrunv6.jpg', array['Comedy', 'Drama'], false, false, true),
('sandeep-bhaiya-2023', 'Sandeep Bhaiya', 'series', 229429, 'tt28227737', 29, 9.0, 77265, 2023, 'Unknown', 'TV', '1 Musim', 'IMDb 9.0', '‘Sandeep Bhaiya’ is a spinoff of the blockbuster webshow TVF Aspirants. It will have a total of eight episodes and is inspired by his iconic character in TVF Aspirants.', '/m9ILwngvdDfznuXFwkle0sEQrjW.jpg', '/pYzW7v7X3qbaR5EJgUoKXfFPiIt.jpg', array['Drama'], false, false, true),
('bleach-thousand-year-blood-war-2022', 'Bleach: Thousand-Year Blood War', 'series', 308329, 'tt14986406', 30, 9.0, 76840, 2022, 'Unknown', 'TV', '1 Musim', 'IMDb 9.0', 'After the brief lull that followed the previous battles, Ichigo and his companions find themselves facing new enemies, who this time manage to strike right at the heart of Soul Society and declare war on the Shinigami. Ghosts from the past, revelations, and relentless, life-or-death battles will fill the adaptation of the final story arc of Tite Kubo’s manga.', '/6gCo1tBFiPFDJL0JHJuzWPurcIr.jpg', '/arGsmUU6DCwPTRrpbZnDmP3myRH.jpg', array['Action', 'Adventure', 'Animation'], false, false, true),
('only-fools-and-horses-1981', 'Only Fools and Horses', 'series', 72, 'tt0081912', 31, 9.0, 66226, 1981, 'Unknown', 'TV', '1 Musim', 'IMDb 9.0', 'Only Fools and Horses.... Is a British sitcom created and written by John Sullivan. Seven series were originally transmitted on BBC One from 1981 to 1991, with sixteen sporadic Christmas specials aired until 2003. In working-class Peckham in south-east London, ambitious market trader Derek ''Del Boy'' Trotter and his younger half-brother Rodney, explore their highs and lows in life, in particular their attempts to get rich. Initially not an immediate hit and receiving little promotion early on, it later achieved consistently high ratings, and the 1996 episode "Time on Our Hands" (originally billed as the series finale) holds the record for the biggest UK audience for a sitcom episode, attracting 24.3 million viewers. The series bears a significant influence on British culture, contributing several words and phrases to the English language.', '/8QznQBwr4aqPIQTiymL7obM3qOK.jpg', '/K8oVAMcE19IvzJsPlRVfDnB4Zq.jpg', array['Comedy'], false, false, true),
('when-life-gives-you-tangerines-2025', 'When Life Gives You Tangerines', 'series', 219246, 'tt26471411', 32, 9.0, 39978, 2025, 'Unknown', 'TV', '1 Musim', 'IMDb 9.0', 'Di Jeju, kisah gadis energik dan pemuda gigih di pulau itu bersemi jadi riwayat panjang penuh kegagalan dan kesuksesan—bukti bahwa cinta bisa bertahan melintasi waktu.', '/1VC3sEFxYXYDqQUCAnvWfUsYg1s.jpg', '/mwczMJeoQrsPERcyP1e900jo3Jv.jpg', array['Drama', 'History', 'Romance'], false, false, true),
('as-if-2021', 'As If', 'series', 115678, 'tt13675832', 33, 9.0, 36907, 2021, 'Unknown', 'TV', '1 Musim', 'IMDb 9.0', 'Yılmaz and İlkkan are two friends who are constantly fighting each other. Their biggest feature is always being able to do things that will turn their ordinary lives upside down. They magnify small events incredibly and give you a nervous breakdown. They are the embodiment of the misfortunes, strange events and despair we experience every day.', '/y1uhSlwcjuzOTxviRDqiMkExnVv.jpg', '/p7VgbdDN2LK41JTavzJ9x3i4ktE.jpg', array['Comedy'], false, false, true),
('taskmaster-2015', 'Taskmaster', 'series', 63404, 'tt4934214', 34, 9.0, 31672, 2015, 'Unknown', 'TV', '1 Musim', 'IMDb 9.0', 'Greg Davies is the Taskmaster, and with the help of his ever-loyal assistant Alex Horne, they will set out to test the wiles, wit, wisdom and skills of five hyper-competitive comedians. Who will be crowned the Taskmaster champion?', '/oHLZyN7G7EpXCHxYdpMcuUNCUgS.jpg', '/wQc6l7RaUi7cPMuCTNnYMKCjvUt.jpg', array['Comedy', 'Game-Show'], false, false, true),
('ramayan-1987', 'Ramayan', 'series', 1990, 'tt0268093', 35, 9.0, 27794, 1987, 'Unknown', 'TV', '1 Musim', 'IMDb 9.0', 'Ramayan is a highly successful and phenomenally popular Indian epic television series created, written, and directed by Ramanand Sagar. The 78 episode series originally aired weekly on Doordarshan from 25 January 1987, to 31 July 1988, on Sundays at 9:30 a.m. IST. It is a television adaptation of the ancient Indian Hindu religious epic of the same name and is primarily based on Valmiki''s Ramayan and Tulsidas'' Ramcharitmanas. It is also partly derived from portions of Kamban''s Ramavataram and other works.', '/gIOtRVKHHyPtyGPsLLhzhSYG1QF.jpg', '/sjaJaXRjp6FrJccBAWup9a8TQ7f.jpg', array['Adventure', 'Drama', 'Family'], false, false, true),
('death-note-2006', 'Death Note', 'series', 13916, 'tt0877057', 36, 8.9, 484379, 2006, 'Unknown', 'TV', '1 Musim', 'IMDb 8.9', 'Pelajar SMA Jepang menemukan buku catatan mistis, yang memberinya kekuatan untuk membunuh siapa pun dengan menuliskan namanya di buku tersebut.', '/tCZFfYTIwrR7n94J6G14Y4hAFU6.jpg', '/koBa94NxTaGe2FoDzlXMuJptsv0.jpg', array['Animation', 'Crime', 'Drama'], false, false, true),
('seinfeld-1989', 'Seinfeld', 'series', 1400, 'tt0098904', 37, 8.9, 385114, 1989, 'Unknown', 'TV', '1 Musim', 'IMDb 8.9', 'A stand-up comedian and his three offbeat friends weather the pitfalls and payoffs of life in New York City in the ''90s. It''s a show about nothing.', '/aCw8ONfyz3AhngVQa1E2Ss4KSUQ.jpg', '/tMRdEsMg9MyXAkcufK9YJEeIaNW.jpg', array['Comedy'], false, false, true),
('firefly-2002', 'Firefly', 'series', 1437, 'tt0303461', 38, 8.9, 302332, 2002, 'Unknown', 'TV', '1 Musim', 'IMDb 8.9', 'In the year 2517, the universe is a vast frontier where lawlessness reigns and adventure awaits! Join Captain Malcolm Reynolds and his ragtag crew aboard the spaceship Serenity as they navigate the fringes of society, battling the oppressive Alliance and facing off against ruthless bounty hunters.', '/vZcKsy4sGAvWMVqLluwYuoi11Kj.jpg', '/te4VJNMipsFQofCkiytuyswGDlV.jpg', array['Adventure', 'Sci-Fi'], false, false, true),
('gravity-falls-2012', 'Gravity Falls', 'series', 40075, 'tt1865718', 39, 8.9, 179886, 2012, 'Unknown', 'TV', '1 Musim', 'IMDb 8.9', 'Twin brother and sister Dipper and Mabel Pines are in for an unexpected adventure when they spend the summer helping their great uncle Stan run a tourist trap in the mysterious town of Gravity Falls, Oregon.', '/qwi3p6PzKfQZ4YXBzv3CP5pO2dE.jpg', '/lhg7eA6CTOCL10QNVdKiyxkgPsL.jpg', array['Adventure', 'Animation', 'Comedy'], false, false, true),
('cowboy-bebop-1998', 'Cowboy Bebop', 'series', 30991, 'tt0213338', 40, 8.9, 170013, 1998, 'Unknown', 'TV', '1 Musim', 'IMDb 8.9', 'In 2071, roughly fifty years after an accident with a hyperspace gateway made the Earth almost uninhabitable, humanity has colonized most of the rocky planets and moons of the Solar System. Amid a rising crime rate, the Inter Solar System Police (ISSP) set up a legalized contract system, in which registered bounty hunters, also referred to as "Cowboys", chase criminals and bring them in alive in return for a reward.', '/xDiXDfZwC6XYC6fxHI1jl3A3Ill.jpg', '/A4PHx94G7mvM3b8vsDJ5HEaQ6uv.jpg', array['Action', 'Adventure', 'Animation'], false, false, true),
('the-pitt-2025', 'The Pitt', 'series', 250307, 'tt31938062', 41, 8.9, 153661, 2025, 'Unknown', 'TV', '1 Musim', 'IMDb 8.9', 'The staff of Pittsburgh''s Trauma Medical Center work around the clock to save lives in an overcrowded and underfunded emergency department.', '/kvFSpESyBZMjaeOJDx7RS3P1jey.jpg', '/7Sgo1XdCrIpJpiNsTPMi9vwKSuC.jpg', array['Drama'], false, false, true),
('the-west-wing-1999', 'The West Wing', 'series', 688, 'tt0200276', 42, 8.9, 99641, 1999, 'Unknown', 'TV', '1 Musim', 'IMDb 8.9', 'The West Wing provides a glimpse into presidential politics in the nation''s capital as it tells the stories of the members of a fictional presidential administration. These interesting characters have humor and dedication that touches the heart while the politics that they discuss touch on everyday life.', '/yqDWr5NAE7m1IWrygYwLyEB6pN0.jpg', '/o6ixncGLOtRPz78vEIy9p1cOn9J.jpg', array['Drama'], false, false, true),
('sousou-no-frieren-2023', 'Sousou no Frieren', 'series', 209867, 'tt22248376', 43, 8.9, 77556, 2023, 'Unknown', 'TV', '1 Musim', 'IMDb 8.9', 'Setelah petualangan 10 tahun dengan pahlawan Himmel dan teman-teman, Frieren mengalahkan raja iblis dan berhasil membawa perdamaian dunia. Frieren yang merupakan seorang elf berusia lebih dari seribu tahun, berjanji untuk pergi menemui Himmel dan kawan-kawan lagi. Lima puluh tahun kemudian, Frieren bertemu dengan Himmel, tetapi Himmel sudah tua dan hanya memiliki sedikit waktu untuk hidup. Setelah menyaksikan kematian Himmel, ia menyadari dirinya tak pernah benar-benar "mengenal seseorang". Frieren yang menyesal kemudian memulai perjalanan untuk lebih "mengenal orang". Dalam perjalanan itu, ia berjumpa dengan berbagai orang dan peristiwa...', '/dqZENchTd7lp5zht7BdlqM7RBhD.jpg', '/rBOnrVlck7BIlGeWVlzYiZeg4l2.jpg', array['Adventure', 'Animation', 'Comedy'], false, false, true),
('persona-2018', 'Persona', 'series', 77994, 'tt7920978', 44, 8.9, 56739, 2018, 'Unknown', 'TV', '1 Musim', 'IMDb 8.9', 'After being diagnosed with Alzheimer''s, a retired judicial officer decides to commit a murder that he had been planning for years.', '/OjvNOeB55tVymgybfWZOD7yXAF.jpg', '/3MfziPWYvHaYwTdi5jxkEscjHVw.jpg', array['Crime', 'Drama', 'Mystery'], false, false, true),
('nathan-for-you-2013', 'Nathan for You', 'series', 58957, 'tt2297757', 45, 8.9, 50061, 2013, 'Unknown', 'TV', '1 Musim', 'IMDb 8.9', 'Self-proclaimed business expert, writer, director and comedian Nathan Fielder helps real small businesses turn a profit with marketing tactics that no ordinary consultant would dare to attempt. From driving foot traffic to an off-the-strip souvenir shop by using Hollywood flair and a Johnny Depp impersonator, to creating a rebate that can only be redeemed by climbing a mountain, to founding a coffee shop called "Dumb Starbucks,” Nathan has always gone to the limit to make his ideas come to life. With his unorthodox approach to problem solving, Nathan’s genuine efforts to do good often draw the real people he encounters into an experience far beyond what they signed up for.', '/6tGXlz61c44onUg6EdRkbhjcaPA.jpg', '/5ix5qtVlLR2O0sgAJp5urHLbGZe.jpg', array['Comedy', 'Documentary'], false, false, true),
('undercover-2011', 'Undercover', 'series', 43424, 'tt1909015', 46, 8.9, 28390, 2011, 'Unknown', 'TV', '1 Musim', 'IMDb 8.9', 'Just an ordinary boy from the Sofia suburbs becomes the first bulgarian undercover cop. Forced by his father when he was young to lie and cheat, Martin becomes the perfect liar. That skill, and also the hatred of the ''underworld'' makes him the perfect match for a dangerous mission - to infiltrate the crime organisation of a rich and powerful businessman. While infiltrating and living in fear of being uncovered, Martin falls in love with the most inappropriate woman - Djaro''s girlfriend, Suni. Just when he gains the trust of the mobsters, it appears that the real enemy is in the police. Martin is alone against all, facing difficult decisions.', '/x1XPfSUFnrBYZgEmFmSwWqVJDjt.jpg', '/ic2zzHB9C2LMsWmmYcMUHA1W8Yq.jpg', array['Action', 'Crime', 'Drama'], false, false, true),
('yeh-meri-family-2018', 'Yeh Meri Family', 'series', 81166, 'tt8595766', 47, 8.9, 27745, 2018, 'Unknown', 'TV', '1 Musim', 'IMDb 8.9', 'Set in the summer of 1998 it is a story about conflicting emotions towards family members from the eyes of a twelve year old.', '/7F33yqUYIzmFQwDibEjPoJxxTXg.jpg', '/iKIfIOPdD0pZsR2KbvTpv4kgsnT.jpg', array['Comedy', 'Drama', 'Family'], false, false, true),
('mahabharat-1988', 'Mahabharat', 'series', 12605, 'tt0158417', 48, 8.9, 27475, 1988, 'Unknown', 'TV', '1 Musim', 'IMDb 8.9', 'A dynastic struggle occurs for the throne of Hastinapur, the kingdom ruled by the Kuru clan, between the Kauravas and Pandavas, collateral branches of the clan, which causes the Kurukshetra War.', '/FZJMIxK1AI1VMbeazdc030Qwat.jpg', '/a7oZ4AMrR7y3q0xm6VHb4FxXGED.jpg', array['Action', 'Adventure', 'Drama'], false, false, true),
('friends-1994', 'Friends', 'series', 1668, 'tt0108778', 49, 8.8, 1194724, 1994, 'Unknown', 'TV', '1 Musim', 'IMDb 8.8', 'Six young people from New York City, on their own and struggling to survive in the real world, find the companionship, comfort and support they get from each other to be the perfect antidote to the pressures of life.', '/2koX1xLkpTQM4IZebYvKysFW1Nh.jpg', '/m3Jev59mJLyUp5bXhY5SVfIBZI0.jpg', array['Comedy', 'Romance'], false, false, true),
('true-detective-2014', 'True Detective', 'series', 46648, 'tt2356777', 50, 8.8, 757871, 2014, 'Unknown', 'TV', '1 Musim', 'IMDb 8.8', 'An American anthology police detective series utilizing multiple timelines in which investigations seem to unearth personal and professional secrets of those involved, both within or outside the law.', '/zYqVTiHK5ZajYcNzAW7qWte5NWS.jpg', '/v8YFr8BbU9qsO8PYIulzTeM6Qk.jpg', array['Crime', 'Drama', 'Mystery'], false, false, true)
on conflict (slug) do update set
  title = excluded.title,
  type = excluded.type,
  tmdb_id = excluded.tmdb_id,
  imdb_id = excluded.imdb_id,
  imdb_rank = excluded.imdb_rank,
  imdb_rating = excluded.imdb_rating,
  imdb_votes = excluded.imdb_votes,
  year = excluded.year,
  country = excluded.country,
  network = excluded.network,
  duration = excluded.duration,
  rating = excluded.rating,
  synopsis = excluded.synopsis,
  poster_path = excluded.poster_path,
  backdrop_path = excluded.backdrop_path,
  genre_names = excluded.genre_names,
  is_published = excluded.is_published,
  is_featured = excluded.is_featured,
  is_trending = excluded.is_trending,
  is_recently_added = excluded.is_recently_added,
  updated_at = now();

insert into public.video_sources (title_id, label, type, url, quality, is_active)
select
  titles.id,
  'NxSha TMDb/IMDb embed',
  'official_embed',
  case when titles.type = 'series' then 'https://web.nxsha.app/embed/tv/' || titles.tmdb_id || '/1/1?sub=id&lang=id' else 'https://web.nxsha.app/embed/movie/' || titles.tmdb_id || '?sub=id&lang=id' end,
  '1080p',
  true
from public.titles
where titles.imdb_id is not null
  and not exists (
    select 1 from public.video_sources where video_sources.title_id = titles.id and video_sources.label = 'NxSha TMDb/IMDb embed'
  );

